def lru_cache_manual(capacity):
    cache = {}
    order = []
    def get(key):
        if key in cache:
            order.remove(key)
            order.append(key)
            return cache[key]
        return -1
    def put(key, value):
        if key in cache:
            order.remove(key)
        elif len(cache) >= capacity:
            oldest = order.pop(0)
            del cache[oldest]
        cache[key] = value
        order.append(key)
    return get, put

